#ifndef GQA_PAGED_DECODE_H32_KV4_D128_PS1_KERNEL_H_
#define GQA_PAGED_DECODE_H32_KV4_D128_PS1_KERNEL_H_

#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <cstdint>
#include <cstdio>
#include <cstdlib>

#ifdef __CUDACC__
#define CUDA_CHECK(ans) { gpuAssert((ans), __FILE__, __LINE__, true); }
inline void gpuAssert(cudaError_t code, const char *file, int line, bool abort) {
    if (code != cudaSuccess) {
        printf("CUDA Error: %s %s %d\n", cudaGetErrorString(code), file, line);
        if (abort) exit(static_cast<int>(code));
    }
}
#else
#define CUDA_CHECK(x) x
#endif

// Constants as per specification
constexpr int NUM_QO_HEADS = 32;
constexpr int NUM_KV_HEADS = 4;
constexpr int HEAD_DIM      = 128;
constexpr int PAGE_SIZE     = 1;

// Kernel launcher declaration
void gqa_paged_decode_h32_kv4_d128_ps1_launcher(
    const __nv_bfloat16* q,               // [B, 32, 128]
    const __nv_bfloat16* k_cache,         // [num_pages, 1, 4, 128]
    const __nv_bfloat16* v_cache,         // [num_pages, 1, 4, 128]
    const int32_t* kv_indptr,             // [B + 1]
    const int32_t* kv_indices,            // [kv_indptr[B]]
    float sm_scale,
    __nv_bfloat16* output,                // [B, 32, 128]
    float* lse,                            // [B, 32]
    int batch_size
);

#endif // GQA_PAGED_DECODE_H32_KV4_D128_PS1_KERNEL_H_

#include "kernel.h"
#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <math.h>
#include <float.h>

#ifndef WARP_SIZE
#define WARP_SIZE 32
#endif

// Safe bfloat16 <-> float conversions without relying on disabled intrinsics
__device__ __forceinline__ float bf16_to_fp32(const __nv_bfloat16 x) {
    union { __nv_bfloat16 bf; unsigned short u16; } cvt;
    cvt.bf = x;
    unsigned int u32 = static_cast<unsigned int>(cvt.u16) << 16;
    union { unsigned int u; float f; } out;
    out.u = u32;
    return out.f;
}
__device__ __forceinline__ __nv_bfloat16 fp32_to_bf16(float f) {
    union { float f; unsigned int u; } in;
    in.f = f;
    // round-to-nearest-even on truncation to bf16
    unsigned int lsb = (in.u >> 16) & 1u;
    unsigned int rounding_bias = 0x7FFFu + lsb;
    unsigned int u_rounded = in.u + rounding_bias;
    unsigned short bf = static_cast<unsigned short>(u_rounded >> 16);
    union { unsigned short u16; __nv_bfloat16 bf; } out;
    out.u16 = bf;
    return out.bf;
}

// Warp reduce sum for float
__inline__ __device__ float warpReduceSum(float val) {
    #pragma unroll
    for (int offset = WARP_SIZE / 2; offset > 0; offset >>= 1) {
        val += __shfl_down_sync(0xffffffff, val, offset);
    }
    return val;
}

template<int HEAD_SIZE>
__global__ __launch_bounds__(HEAD_SIZE, 2)
void gqa_paged_decode_h32_kv4_d128_ps1_kernel(
    const __nv_bfloat16* __restrict__ q,               // [B, 32, 128]
    const __nv_bfloat16* __restrict__ k_cache,         // [num_pages, 1, 4, 128]
    const __nv_bfloat16* __restrict__ v_cache,         // [num_pages, 1, 4, 128]
    const int32_t* __restrict__ kv_indptr,             // [B + 1]
    const int32_t* __restrict__ kv_indices,            // [kv_indptr[B]]
    float sm_scale,
    __nv_bfloat16* __restrict__ output,                // [B, 32, 128]
    float* __restrict__ lse,                           // [B, 32]
    int batch_size
) {
    static_assert(HEAD_SIZE == 128, "HEAD_SIZE must be 128");
    static_assert(WARP_SIZE == 32, "Assuming warp size 32");

    const int tid = threadIdx.x;

    const int global_block = blockIdx.x;
    const int h = global_block % NUM_QO_HEADS;
    const int b = global_block / NUM_QO_HEADS;
    if (b >= batch_size) return;

    // Calculate kv head index for GQA (ratio=8)
    const int gqa_ratio = NUM_QO_HEADS / NUM_KV_HEADS; // 8
    const int kv_head = h / gqa_ratio;                 // [0..3]

    // Shared scalars for softmax streaming
    __shared__ float s_m;
    __shared__ float s_s;
    __shared__ float s_alpha_old;
    __shared__ float s_w;
    __shared__ float warp_sums[HEAD_SIZE / WARP_SIZE]; // 128/32 = 4

    // Load q vector element into register
    const int q_offset_base = ((b * NUM_QO_HEADS + h) * HEAD_SIZE);
    float q_reg = bf16_to_fp32(q[q_offset_base + tid]);

    // Determine token range for this batch element
    const int32_t start = kv_indptr[b];
    const int32_t end   = kv_indptr[b + 1];
    const int32_t num_tokens = end - start;

    // Handle empty KV for this element
    if (num_tokens <= 0) {
        output[q_offset_base + tid] = fp32_to_bf16(0.0f);
        if (tid == 0) {
            lse[b * NUM_QO_HEADS + h] = -INFINITY;
        }
        return;
    }

    // Register accumulator for output vector (unnormalized)
    float out_reg = 0.f;

    // Initialize streaming softmax accumulators
    if (tid == 0) {
        s_m = -INFINITY;
        s_s = 0.0f;
        s_alpha_old = 1.0f;
        s_w = 0.0f;
    }
    __syncthreads();

    // Iterate over tokens (pages since page_size=1)
    for (int32_t idx = start; idx < end; ++idx) {
        const int32_t page_id = kv_indices[idx];

        // Offsets for K and V for the chosen kv_head
        const int kv_base = (page_id * NUM_KV_HEADS + kv_head) * HEAD_SIZE;

        // Compute dot(q, k_i) across threads
        float k_val = bf16_to_fp32(k_cache[kv_base + tid]);
        float partial = q_reg * k_val;

        // Intra-warp reduction
        float sum = warpReduceSum(partial);

        // Write per-warp sums to shared mem
        const int warp_id = tid / WARP_SIZE;
        const int lane = tid % WARP_SIZE;
        if (lane == 0) {
            warp_sums[warp_id] = sum;
        }
        __syncthreads();

        if (tid == 0) {
            // Reduce across warps
            float total = 0.f;
            #pragma unroll
            for (int w = 0; w < HEAD_SIZE / WARP_SIZE; ++w) {
                total += warp_sums[w];
            }
            float dot = total * sm_scale;

            // Streaming softmax update
            float new_m = s_m;
            if (dot > new_m) new_m = dot;
            float alpha = (s_m == -INFINITY) ? 0.0f : __expf(s_m - new_m);
            float w = __expf(dot - new_m);
            float new_s = s_s * alpha + w;

            s_alpha_old = alpha;
            s_w = w;
            s_m = new_m;
            s_s = new_s;
        }
        __syncthreads();

        // Accumulate V with updated scaling: out = out*alpha_old + w * v_i
        float v_val = bf16_to_fp32(v_cache[kv_base + tid]);
        out_reg = fmaf(s_w, v_val, out_reg * s_alpha_old);

        __syncthreads();
    }

    // Normalize output and write back
    float inv_s = 0.0f;
    if (tid == 0) {
        inv_s = 1.0f / s_s;
        warp_sums[0] = inv_s; // reuse shared memory as a single-scalar broadcast
    }
    __syncthreads();
    inv_s = warp_sums[0];

    float out_final = out_reg * inv_s;
    output[q_offset_base + tid] = fp32_to_bf16(out_final);

    // Compute LSE base-2: logsumexp(logits_scaled) in base 2
    if (tid == 0) {
        float lse_nat = logf(s_s) + s_m;  // natural log
        float lse_base2 = lse_nat / logf(2.0f);
        lse[b * NUM_QO_HEADS + h] = lse_base2;
    }
}

void gqa_paged_decode_h32_kv4_d128_ps1_launcher(
    const __nv_bfloat16* q,
    const __nv_bfloat16* k_cache,
    const __nv_bfloat16* v_cache,
    const int32_t* kv_indptr,
    const int32_t* kv_indices,
    float sm_scale,
    __nv_bfloat16* output,
    float* lse,
    int batch_size
) {
    const int blocks = batch_size * NUM_QO_HEADS;
    if (blocks <= 0) return;
    const dim3 grid(blocks);
    const dim3 block(HEAD_DIM); // 128 threads

    gqa_paged_decode_h32_kv4_d128_ps1_kernel<HEAD_DIM>
        <<<grid, block, 0, 0>>>(
            q, k_cache, v_cache, kv_indptr, kv_indices, sm_scale,
            output, lse, batch_size
        );
    CUDA_CHECK(cudaGetLastError());
}

#include <torch/extension.h>
#include <vector>
#include <stdexcept>
#include <string>
#include <sstream>
#include <cuda_runtime.h>
#include "kernel.h"

static inline void checkCudaDevice(const torch::Tensor& t, const std::string& name) {
    if (!t.device().is_cuda()) {
        std::ostringstream oss;
        oss << "Tensor '" << name << "' must be on CUDA device.";
        throw std::invalid_argument(oss.str());
    }
}

static inline void checkContiguous(const torch::Tensor& t, const std::string& name) {
    if (!t.is_contiguous()) {
        std::ostringstream oss;
        oss << "Tensor '" << name << "' must be contiguous.";
        throw std::invalid_argument(oss.str());
    }
}

static inline void checkDtype(const torch::Tensor& t, at::ScalarType dtype, const std::string& name) {
    if (t.scalar_type() != dtype) {
        std::ostringstream oss;
        oss << "Tensor '" << name << "' must have dtype " << c10::toString(dtype)
            << " but got " << c10::toString(t.scalar_type());
        throw std::invalid_argument(oss.str());
    }
}

std::vector<torch::Tensor> run(
    torch::Tensor q,            // [B, 32, 128], bfloat16
    torch::Tensor k_cache,      // [num_pages, 1, 4, 128], bfloat16
    torch::Tensor v_cache,      // [num_pages, 1, 4, 128], bfloat16
    torch::Tensor kv_indptr,    // [B + 1], int32
    torch::Tensor kv_indices,   // [kv_indptr[-1]], int32
    double sm_scale             // scalar float
) {
    try {
        // Device checks
        checkCudaDevice(q, "q");
        checkCudaDevice(k_cache, "k_cache");
        checkCudaDevice(v_cache, "v_cache");
        checkCudaDevice(kv_indptr, "kv_indptr");
        checkCudaDevice(kv_indices, "kv_indices");

        // Dtype checks
        checkDtype(q, at::kBFloat16, "q");
        checkDtype(k_cache, at::kBFloat16, "k_cache");
        checkDtype(v_cache, at::kBFloat16, "v_cache");
        checkDtype(kv_indptr, at::kInt, "kv_indptr");
        checkDtype(kv_indices, at::kInt, "kv_indices");

        // Contiguity
        checkContiguous(q, "q");
        checkContiguous(k_cache, "k_cache");
        checkContiguous(v_cache, "v_cache");
        checkContiguous(kv_indptr, "kv_indptr");
        checkContiguous(kv_indices, "kv_indices");

        // Shape checks
        TORCH_CHECK(q.dim() == 3, "q must be [B, 32, 128]");
        TORCH_CHECK(q.size(1) == NUM_QO_HEADS, "q second dimension must be 32");
        TORCH_CHECK(q.size(2) == HEAD_DIM, "q head_dim must be 128");

        TORCH_CHECK(k_cache.dim() == 4, "k_cache must be [num_pages, 1, 4, 128]");
        TORCH_CHECK(k_cache.size(1) == PAGE_SIZE, "k_cache page_size must be 1");
        TORCH_CHECK(k_cache.size(2) == NUM_KV_HEADS, "k_cache num_kv_heads must be 4");
        TORCH_CHECK(k_cache.size(3) == HEAD_DIM, "k_cache head_dim must be 128");
        TORCH_CHECK(v_cache.sizes() == k_cache.sizes(), "v_cache must have same shape as k_cache");

        const int64_t B = q.size(0);
        TORCH_CHECK(kv_indptr.dim() == 1, "kv_indptr must be 1D");
        TORCH_CHECK(kv_indptr.size(0) == B + 1, "kv_indptr length must be batch_size + 1");
        TORCH_CHECK(kv_indices.dim() == 1, "kv_indices must be 1D");

        // Check kv_indices length equals kv_indptr[-1]
        int32_t last_ind = 0;
        {
            const int32_t* kv_indptr_ptr = kv_indptr.data_ptr<int32_t>();
            // Copy last element from device to host
            CUDA_CHECK(cudaMemcpy(&last_ind, kv_indptr_ptr + B, sizeof(int32_t), cudaMemcpyDeviceToHost));
        }
        TORCH_CHECK(kv_indices.size(0) == last_ind,
                    "num_kv_indices must equal kv_indptr[-1]");

        // Prepare outputs
        auto options_bf16 = q.options().dtype(at::kBFloat16);
        auto options_f32  = q.options().dtype(at::kFloat);
        torch::Tensor output = torch::empty({B, NUM_QO_HEADS, HEAD_DIM}, options_bf16);
        torch::Tensor lse = torch::empty({B, NUM_QO_HEADS}, options_f32);

        // Raw pointers
        const __nv_bfloat16* q_ptr        = reinterpret_cast<const __nv_bfloat16*>(q.data_ptr<c10::BFloat16>());
        const __nv_bfloat16* k_ptr        = reinterpret_cast<const __nv_bfloat16*>(k_cache.data_ptr<c10::BFloat16>());
        const __nv_bfloat16* v_ptr        = reinterpret_cast<const __nv_bfloat16*>(v_cache.data_ptr<c10::BFloat16>());
        const int32_t* kv_indptr_ptr      = kv_indptr.data_ptr<int32_t>();
        const int32_t* kv_indices_ptr     = kv_indices.data_ptr<int32_t>();
        __nv_bfloat16* out_ptr            = reinterpret_cast<__nv_bfloat16*>(output.data_ptr<c10::BFloat16>());
        float* lse_ptr                    = lse.data_ptr<float>();

        // Launch kernel
        gqa_paged_decode_h32_kv4_d128_ps1_launcher(
            q_ptr, k_ptr, v_ptr,
            kv_indptr_ptr, kv_indices_ptr,
            static_cast<float>(sm_scale), out_ptr, lse_ptr,
            static_cast<int>(B)
        );

        // Synchronize and check errors
        CUDA_CHECK(cudaDeviceSynchronize());

        return {output, lse};
    } catch (const c10::Error& e) {
        throw std::runtime_error(std::string("Torch error in run(): ") + e.what());
    } catch (const std::exception& e) {
        throw std::runtime_error(std::string("Error in run(): ") + e.what());
    }
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "Kernel execution function",
          py::arg("q"),
          py::arg("k_cache"),
          py::arg("v_cache"),
          py::arg("kv_indptr"),
          py::arg("kv_indices"),
          py::arg("sm_scale"));
}
